sp_widget.client_script:
api.controller=function($scope) {
  /* widget controller */
  var c = this;

	$scope.$on('summary.refresh', function() {
    c.server.update(); // reload data from server
  });
};

sp_widget.script:
(function() {
  /* populate the 'data' object */
  /* e.g., data.table = $sp.getValue('table'); */

	var plansysid= $sp.getParameter('sys_id');
	var table=$sp.getParameter("table")

	if(plansysid && table)
		{


					var gPlan= new GlideRecordSecure(table);
					if(gPlan.get(plansysid))

					{
						data.plan_name=gPlan.getDisplayValue('plan_name');
						data.status=gPlan.getDisplayValue('status');
					}



	 				var grEarning = new GlideAggregate('x_ctans_incentnow_earning_rule');
					grEarning.addQuery('plan', plansysid);
					grEarning.addAggregate('COUNT');
					grEarning.query();

					if (grEarning.next()) {
							data.earningrules = parseInt(grEarning.getAggregate('COUNT'), 10);
					}


					var grLook = new GlideAggregate('x_ctans_incentnow_lookup_rule');
					grLook.addQuery('plan', plansysid);
					grLook.addAggregate('COUNT');
					grLook.query();

					if (grLook.next()) {
							data.commissionrules = parseInt(grLook.getAggregate('COUNT'), 10);
					}



		}


})();
